func gcd(a, b int) int {
	if b == 0 {
		return a
	}
	return gcd(b, a%b)
}

java.code:
class Solution {
    public boolean isReachable(int targetX, int targetY) {
        int x = gcd(targetX, targetY);
        return (x & (x - 1)) == 0;
    }

    private int gcd(int a, int b) {
        return b == 0 ? a : gcd(b, a % b);
    }
}

